import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Link } from 'react-router-dom';
import {
  ChevronRight,
  ChevronUp,
  ChevronDown,
  Zap,
  Leaf,
  Clock,
  Award
} from 'lucide-react';
import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';

import Button from '../components/Button';
import MealCard from '../components/MealCard';
import PlanCard from '../components/PlanCard';
import ReviewCard from '../components/ReviewCard';
import { getMeals, getPlans, getReviews } from '../api/services';
import { foodImages } from '../data/foodImages';

gsap.registerPlugin(ScrollTrigger);

const Home = () => {
  const [meals, setMeals] = useState([]);
  const [plans, setPlans] = useState([]);
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeIndex, setActiveIndex] = useState(0);
  const [orbitRotation, setOrbitRotation] = useState(0);

  const popularBgRef = useRef(null);
  const plansBgRef = useRef(null);
  const reviewsBgRef = useRef(null);

  const ORBIT_RADIUS = 320;
  const ROTATION_STEP = 60;
  const ORBIT_IMAGE_COUNT = 4;

  /* ---------------- FETCH DATA ---------------- */
  useEffect(() => {
    const fetchData = async () => {
      try {
        const [mealsRes, plansRes, reviewsRes] = await Promise.all([
          getMeals(),
          getPlans(),
          getReviews(),
        ]);
        setMeals(mealsRes.data.slice(0, 6));
        setPlans(plansRes.data);
        setReviews(reviewsRes.data.slice(0, 3));
      } catch (err) {
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  /* ---------------- AUTO ORBIT ---------------- */
  useEffect(() => {
    const interval = setInterval(() => {
      setOrbitRotation((prev) => prev - 60);
      setActiveIndex((prev) =>
        prev === foodImages.length - 1 ? 0 : prev + 1
      );
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  /* ---------------- GSAP BACKGROUNDS ---------------- */
  useEffect(() => {
    gsap.fromTo(
      popularBgRef.current,
      { scale: 1.15 },
      {
        scale: 1,
        scrollTrigger: {
          trigger: popularBgRef.current,
          start: 'top bottom',
          end: 'bottom top',
          scrub: true,
        },
      }
    );

    gsap.fromTo(
      plansBgRef.current,
      { y: 100 },
      {
        y: -100,
        scrollTrigger: {
          trigger: plansBgRef.current,
          start: 'top bottom',
          end: 'bottom top',
          scrub: true,
        },
      }
    );

    gsap.fromTo(
      reviewsBgRef.current,
      { y: 150 },
      {
        y: -150,
        scrollTrigger: {
          trigger: reviewsBgRef.current,
          start: 'top bottom',
          end: 'bottom top',
          scrub: true,
        },
      }
    );
  }, []);

  /* ---------------- ORBIT HELPERS ---------------- */
  const getOrbitImages = () => {
    const images = [];
    for (let i = 0; i < ORBIT_IMAGE_COUNT; i++) {
      const baseAngle = (i * 360) / ORBIT_IMAGE_COUNT;
      images.push({
        index: (activeIndex + i) % foodImages.length,
        baseAngle,
      });
    }
    return images;
  };

  const orbitImages = getOrbitImages();
  const currentFood = foodImages[activeIndex];

  /* ---------------- WHY GALOBA ---------------- */
  const whyFeatures = [
    { icon: Zap, title: 'High Protein', description: 'Fuel your workouts.' },
    { icon: Leaf, title: 'Fresh Ingredients', description: 'Daily sourced.' },
    { icon: Clock, title: 'Quick Delivery', description: '30 min delivery.' },
    { icon: Award, title: 'Certified Nutrition', description: 'Expert planned.' },
  ];

  /* ====================================================== */
  return (
    <div className="bg-neutral-bg">

      {/* ---------------- POPULAR MEALS ---------------- */}
      <section className="relative py-20 px-6 overflow-hidden">
        <div
          ref={popularBgRef}
          className="absolute inset-0 -z-10 bg-cover bg-center"
          style={{
            backgroundImage:
              "url('https://images.unsplash.com/photo-1504674900247-087703934569?auto=format&fit=crop&w=1920&q=80')",
          }}
        >
          <div className="absolute inset-0 bg-black/60" />
        </div>

        <div className="max-w-7xl mx-auto">
          <h2 className="text-4xl font-bold text-white text-center mb-12">
            Popular Meals
          </h2>

          {loading ? (
            <p className="text-white text-center">Loading...</p>
          ) : (
            <div className="grid md:grid-cols-3 gap-8">
              <AnimatePresence>
                {meals.map((meal, i) => (
                  <motion.div
                    key={meal.id}
                    initial={{ opacity: 0, y: 50 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.1 }}
                    viewport={{ once: true }}
                  >
                    <MealCard meal={meal} />
                  </motion.div>
                ))}
              </AnimatePresence>
            </div>
          )}
        </div>
      </section>

      {/* ---------------- SUBSCRIPTION PLANS ---------------- */}
      <section className="relative py-20 px-6 overflow-hidden">
        <div
          ref={plansBgRef}
          className="absolute inset-0 -z-10 bg-cover bg-center"
          style={{
            backgroundImage:
              "url('https://images.unsplash.com/photo-1543353071-087092ec393a?auto=format&fit=crop&w=1920&q=80')",
          }}
        >
          <div className="absolute inset-0 bg-white/90" />
        </div>

        <div className="max-w-7xl mx-auto">
          <h2 className="text-4xl font-bold text-center mb-12">
            Subscription Plans
          </h2>

          <div className="grid md:grid-cols-3 gap-8">
            {plans.map((plan, i) => (
              <motion.div
                key={plan.id}
                whileHover={{ y: -10 }}
                initial={{ opacity: 0, y: 40 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.15 }}
                viewport={{ once: true }}
              >
                <PlanCard plan={plan} isPopular={i === 1} />
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* ---------------- REVIEWS ---------------- */}
      <section className="relative py-20 px-6 overflow-hidden">
        <div
          ref={reviewsBgRef}
          className="absolute inset-0 -z-10 bg-cover bg-center"
          style={{
            backgroundImage:
              "url('https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?auto=format&fit=crop&w=1920&q=80')",
          }}
        >
          <div className="absolute inset-0 bg-black/80" />
        </div>

        <div className="max-w-7xl mx-auto">
          <h2 className="text-4xl font-bold text-white text-center mb-12">
            Customer Reviews
          </h2>

          <div className="grid md:grid-cols-3 gap-8">
            {reviews.map((review, i) => (
              <motion.div
                key={review.id}
                initial={{ opacity: 0, y: 50 }}
                whileInView={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.15 }}
                viewport={{ once: true }}
              >
                <ReviewCard review={review} />
              </motion.div>
            ))}
          </div>
        </div>
      </section>

    </div>
  );
};

export default Home;
